#include <stdio.h>

int main() {
    int T, N, K;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d %d", &N, &K) != 2) return 0;
        int a[1005];
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
        }
        long long cur = 0;
        for (int i = 0; i < K; ++i) cur += a[i];
        long long best = cur;
        for (int i = K; i < N; ++i) {
            cur += a[i] - a[i - K];
            if (cur > best) best = cur;
        }
        printf("%lld\n", best);
    }
    return 0;
}

